-- Botox / Neurotoxins (1-15)
(bid, 'Botox — Forehead Lines', 'Smooths horizontal forehead lines with precise Botox injections. Results last 3-4 months.', 250.00, 30, 'Botox & Neurotoxins', true, '[]', '{"downtime_required":"None","numbing_included":false,"aftercare_instructions":"Avoid lying down for 4 hours. No exercise for 24 hours."}'),
