(bid, 'Botox — Crow''s Feet', 'Softens fine lines around the eyes that appear when smiling or squinting.', 225.00, 20, 'Botox & Neurotoxins', true, '[]', '{"downtime_required":"None","numbing_included":false,"aftercare_instructions":"Avoid makeup on treated area for 4 hours."}'),
(bid, 'Botox — Full Upper Face', 'Comprehensive treatment of forehead, frown lines, and crow''s feet in one session.', 650.00, 45, 'Botox & Neurotoxins', true, '[]', '{"downtime_required":"None","numbing_included":false,"aftercare_instructions":"Stay upright for 4 hours. Avoid strenuous exercise for 24 hours."}'),
(bid, 'Botox — Bunny Lines', 'Smooths wrinkles on the sides of the nose that appear when scrunching.', 150.00, 15, 'Botox & Neurotoxins', true, '[]', '{"downtime_required":"None","numbing_included":false,"aftercare_instructions":"No rubbing or massaging the nose area."}'),
(bid, 'Botox — Lip Flip', 'Subtle enhancement that relaxes the upper lip to create a fuller appearance without filler.', 175.00, 15, 'Botox & Neurotoxins', true, '[]', '{"downtime_required":"None","numbing_included":false,"aftercare_instructions":"Avoid using straws for 48 hours. Results appear in 5-7 days."}'),
(bid, 'Botox — Chin Dimpling', 'Relaxes the mentalis muscle to smooth a dimpled or pebbled chin texture.', 150.00, 15, 'Botox & Neurotoxins', true, '[]', '{"downtime_required":"None","numbing_included":false,"aftercare_instructions":"Minimal aftercare needed. Avoid touching treated area."}'),
(bid, 'Botox — Gummy Smile Correction', 'Reduces excessive gum display when smiling by relaxing the upper lip elevator muscles.', 200.00, 20, 'Botox & Neurotoxins', true, '[]', '{"downtime_required":"None","numbing_included":false,"aftercare_instructions":"May feel mild tightness. Results in 5-10 days."}'),
(bid, 'Botox — Jawline Slimming (Masseter)', 'Reduces jaw width by relaxing the masseter muscles for a slimmer facial profile.', 450.00, 30, 'Botox & Neurotoxins', true, '[]', '{"downtime_required":"None","numbing_included":false,"aftercare_instructions":"Avoid chewing gum for 2 weeks. Full results in 4-6 weeks."}'),
(bid, 'Botox — Neck Bands (Platysma)', 'Smooths vertical neck bands for a more youthful neck and jawline appearance.', 350.00, 30, 'Botox & Neurotoxins', true, '[]', '{"downtime_required":"None","numbing_included":false,"aftercare_instructions":"Avoid neck exercises for 48 hours."}'),
(bid, 'Botox — Hyperhidrosis (Underarms)', 'Treats excessive underarm sweating with Botox injections. Results last 6-9 months.', 900.00, 45, 'Botox & Neurotoxins', true, '[]', '{"downtime_required":"None","numbing_included":true,"aftercare_instructions":"Avoid antiperspirant for 24 hours. No exercise day of treatment."}'),
(bid, 'Botox — Hyperhidrosis (Palms)', 'Reduces excessive palm sweating for improved confidence and comfort.', 1000.00, 60, 'Botox & Neurotoxins', true, '[]', '{"downtime_required":"1-2 days","numbing_included":true,"aftercare_instructions":"Temporary hand weakness possible. Avoid gripping heavy objects for 48 hours."}'),
(bid, 'Dysport — Full Upper Face', 'Alternative neurotoxin that spreads naturally for a softer, more diffused result.', 600.00, 45, 'Botox & Neurotoxins', true, '[]', '{"downtime_required":"None","numbing_included":false,"aftercare_instructions":"Same aftercare as Botox. Results may appear 1-2 days faster than Botox."}'),
